mapper.select:
select ifnull(sum(balance),0) totalBalance,
        ifnull(sum(frozen),0) totalFrozen
from a_asset_flow

    and uid = #{uid}

        and `ymd` = #{day}


        and create_at >= #{invalidAt}

    and scene in

        #{item}

select uid,symbol,`ymd`,scene, ifnull(sum(balance),0) balance, ifnull(sum(frozen),0) frozen
from a_asset_flow


            and symbol = #{symbol}


            and clear_day = #{day}


            and scene in

                #{item}



group by uid,symbol,`ymd`,scene

mapper.update:
update a_asset_flow set clear_day = #{day}


        and symbol = #{symbol}

    and clear_day is null

        and `ymd` < #{day}


        and scene in

            #{item}

mapper.select:
select  ifnull(sum(case ff.uid when #{uid} then ff.balance else 0 end), 0) myBalance,
        ifnull(sum(case ff.uid when #{uid} then ff.frozen else 0 end), 0) myFrozen,
        ifnull(sum(ff.balance),0) totalBalance,
        ifnull(sum(ff.frozen),0) totalFrozen
from a_asset_flow ff


        and ff.`ymd` = #{day}


        and ff.create_at >= #{invalidAt}

    and ff.scene in

        #{item}

    and exists (
        WITH RECURSIVE CTE AS (
        select b.id,b.pid from u_member b where b.deleted = 0 and b.id = #{uid}
        union all
        select a.id,a.pid from u_member a inner join cte c on a.pid = c.id where a.deleted = 0
        )
        select 1 from CTE ct where ct.id = ff.uid
    )

select ifnull(sum(balance), 0)
from a_asset_flow


        and `type` = #{type}


        and uid = #{uid}


        and symbol = #{symbol}


        and `ymd` = #{day}


        and scene in

            #{item}
